+fn json_contains_backtrack(
+    expected_idx: usize,
+    candidates: &[Vec<usize>],
+    used: &mut [bool],
+) -> bool {
+    if expected_idx == candidates.len() {
+        return true;
+    }
+    for &candidate in &candidates[expected_idx] {
+        if used[candidate] {
+            continue;
+        }
+        used[candidate] = true;
+        if json_contains_backtrack(expected_idx + 1, candidates, used) {
+            return true;
+        }
+        used[candidate] = false;
+    }
+    false
+}
